#include "hardtanh_custom_tiling.h"
#include "register/op_def_registry.h"
#include "tiling/tiling_api.h"

namespace optiling {
const uint32_t BLOCK_DIM = 8;
const uint32_t TILE_NUM = 8;
const uint32_t SIZEFLAG = 0; // 0: use min tempBuffer; 1: use max tempBuffer; 2: no shared tmp

static ge::graphStatus TilingFunc(gert::TilingContext* context)
{
    HardtanhCustomTilingData tiling;

    uint32_t totalLength = context->GetInputShape(0)->GetOriginShape().GetShapeSize();
    context->SetBlockDim(BLOCK_DIM);
    tiling.set_totalLength(totalLength);
    tiling.set_tileNum(TILE_NUM);

    std::vector<int64_t> shapeVec = {static_cast<int64_t>(totalLength)};
    ge::Shape srcShape(shapeVec);
    uint32_t typeSize = sizeof(float);
    uint32_t maxValue = 0;
    uint32_t minValue = 0;
    bool isReuseSource = false;
    AscendC::GetClampMaxMinTmpSize(srcShape, typeSize, isReuseSource, maxValue, minValue);

    if (SIZEFLAG == 0) {
        tiling.set_tmpSize(minValue);
    } else if (SIZEFLAG == 1) {
        tiling.set_tmpSize(maxValue);
    } else {
        tiling.set_tmpSize(0);
    }

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(), context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());
    context->SetTilingKey(1);

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
}

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext* context)
{
    const gert::Shape* in_shape = context->GetInputShape(0);
    gert::Shape* out_shape = context->GetOutputShape(0);
    *out_shape = *in_shape;
    return GRAPH_SUCCESS;
}
static ge::graphStatus InferDataType(gert::InferDataTypeContext *context)
{
    const auto inputDataType = context->GetInputDataType(0);
    context->SetOutputDataType(0, inputDataType);
    return ge::GRAPH_SUCCESS;
}
}

